    - \frac{1}{N}\sum_{i=1}^N \frac{1}{G}\sum_{j=1}^G \frac{1}{|\tau_j|} \sum_{t=1}^{|\tau_j|} 
        \pi_\theta (\tau_{i,j,t} |q_i, \tau_{i,j, <t} )  \hat{A}_{i,j},
