\begin{equation}\label{eq_SRFT_grad}
    \nabla \mathcal{J}_{SRFT} = -\nabla \cL_{SRFT} =     \frac{1}{N}\sum_{i=1}^N \frac{1}{G}\sum_{j=1}^G \frac{1}{|\tau_j|} \sum_{t=1}^{|\tau_j|} 
